import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// Create axios instance
const api = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add request interceptor to add auth token
api.interceptors.request.use(
  (config) => {
    const userData = localStorage.getItem('user');
    if (userData) {
      try {
        const user = JSON.parse(userData);
        if (user.token) {
          config.headers.Authorization = `Bearer ${user.token}`;
        }
      } catch (error) {
        console.error('Error parsing user data:', error);
      }
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Add response interceptor to handle auth errors
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      // Token expired or invalid, redirect to login
      localStorage.removeItem('user');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// Authentication APIs
export const authAPI = {
  login: (email: string, password: string) => 
    api.post('/users/login', { email, password }),
  register: (name: string, email: string, password: string, role: string = 'user') => 
    api.post('/users/register', { name, email, password, role }),
};

// Products API
export const productsAPI = {
  getAll: () => api.get('/products'),
  getById: (id: string) => api.get(`/products/${id}`),
  create: (productData: any) => api.post('/products', productData),
  update: (id: string, productData: any) => api.put(`/products/${id}`, productData),
  delete: (id: string) => api.delete(`/products/${id}`),
};

// Categories API
export const categoriesAPI = {
  getAll: () => api.get('/categories'),
  getById: (id: string) => api.get(`/categories/${id}`),
  create: (categoryData: any) => api.post('/categories', categoryData),
  update: (id: string, categoryData: any) => api.put(`/categories/${id}`, categoryData),
  delete: (id: string) => api.delete(`/categories/${id}`),
};

// Orders API
export const ordersAPI = {
  getAll: () => api.get('/orders'),
  getById: (id: string) => api.get(`/orders/${id}`),
  create: (orderData: any) => api.post('/orders', orderData),
  update: (id: string, orderData: any) => api.put(`/orders/${id}`, orderData),
  updateStatus: (id: string, status: string) => api.put(`/orders/${id}/status`, { status }),
  delete: (id: string) => api.delete(`/orders/${id}`),
};

// Statistics API (fallback implementation)
export const fetchStatistics = async () => {
  try {
    // Try to get actual stats from a dedicated endpoint
    const response = await api.get('/stats');
    return response.data;
  } catch (error) {
    // Fallback: calculate stats from existing data
    const [products, orders, categories] = await Promise.all([
      productsAPI.getAll(),
      ordersAPI.getAll(),
      categoriesAPI.getAll(),
    ]);

    const totalRevenue = orders.data.reduce((sum: number, order: any) => {
      return sum + (order.totalPrice || 0);
    }, 0);

    return {
      totalProducts: products.data.length,
      totalOrders: orders.data.length,
      totalRevenue,
      totalCategories: categories.data.length,
      pendingOrders: orders.data.filter((order: any) => order.status === 'pending').length,
    };
  }
};

export default api;
